INSERT IGNORE INTO `Classroomassignment` (`id`, `classroomId`, `lessonId`, `title`, `description`, `type`, `durationMinutes`, `questionHtml`, `questionDocx`, `answerTemplate`, `maxScore`, `isPublished`, `createdBy`, `createdAt`, `updatedAt`) VALUES
('cmmrf3ok90001akdvi216pf7e', 'cmmrcte7c001e6utn7nlx08pe', 'cmmralrck00116utn4i77xgvh', 'Bài ki?m tra - Tuple và Dictionary: Cấu trúc dữ liệu có tổ chức và an toàn', NULL, 'test', 45, '<p>CỘNG HOÀ XÃ HỘI CHỦ NGHĨA VIỆT NAM</p><p><strong>Độc lập - Tự do - Hạnh phúc</strong></p><p>Ảnh mầu</p><p>4x6cm</p><p>(có đóng dấu giáp lai của của cơ quan xác nhận lý lịch)</p><p><img src=\"data:image/png;base64,\" /></p><p><strong>PHIẾU TUYỂN SINH</strong></p><p>(KỲ THI TUYỂN SINH ĐÀO TẠO TỪ XA TRÌNH ĐỘ ĐẠI HỌC)</p><p><strong><em>Kính gửi :</em></strong> 	<strong>Hội đồng tuyển sinh từ xa trình độ đại học</strong></p><p><strong>Học viện Công nghệ Bưu chính Viễn thông</strong></p><p>Tên tôi là: Nguyễn Anh Đức                                                                         Nam, nữ: Nam</p><p>Có nguyện vọng xin dự tuyển TỪ XA TRÌNH ĐỘ ĐẠI HỌC  năm 2025	</p><p>Ngành học: Công nghệ thông tin</p><p> SƠ YỀU LÝ LỊCH</p><p><strong>1 Phần bản thân</strong>:</p><p>Họ và tên: Nguyễn Anh Đức                                                        Bí danh: DanCru Nguyễn</p><p>Tên thường gọi: Anh Đức</p><p>Sinh ngày 29 tháng 09 năm 2005 Tại: Thành phố Thanh Hóa</p><p>Nguyên quán: Phố Hưng Thuận, phường Quảng Phú, Thành phố Thanh Hóa</p><p>	</p><p>Nơi đăng ký thường trú hiện nay: Phố Hưng Thuận, phường Quảng Phú, Thành phố Thanh Hóa</p><p>Dân tộc: Kinh           Tôn giáo: Không                  Điện thoại:0822153447</p><p>Số CMT/Thẻ CCCD: 038205000950            Email: nguyenanhduc2909@gmail.com</p><p>Thành phần gia đình sau cải cách ruộng đất (hoặc cải tạo công thương nghiệp)	</p><p>	</p><p>Thành phần bản thân hiện nay: 	</p><p>Trình độ văn hoá: ( Đã có bằng tốt nghiệp THPT, BTTH) 12/12 Năm tốt nghiệp: 2023</p><p>Trình độ chuyên môn:  Cao đẳng    Loại hình đào tạo: Chính quy</p><p>Chuyên ngành đào tạo: Công nghệ thông tin</p><p>Ngành: Công nghệ thông tin       Chuyên ngành: Lập trình web</p><p>Ký hiệu bằng: Chưa có         Số vào sổ: Chưa có</p><p>Nơi cấp bằng: Chưa có</p><p>Trình độ ngoại ngữ: A2</p><p><strong>2.  Quá trình học tập và làm việc của bản thân ( </strong><em>Khai từ khi 15 tuổi cho đến ngày khai lý lịch, phải khai liên tục, rõ công việc cụ thể, tên đơn vị và địa chỉ của đơn vị</em><strong>)</strong>:</p><table><tr><td colspan=\"2\"><p><em>Thời gian</em></p></td><td rowspan=\"2\"><p><em>Học hoặc làm việc gì</em></p></td><td rowspan=\"2\"><p><em>Tên đơn vị</em></p></td><td rowspan=\"2\"><p><em>Địa chỉ đơn vị</em></p></td></tr><tr><td><p><em>Từ</em></p></td><td><p><em>Đến</em></p></td></tr><tr><td><p>2019</p></td><td><p>2022</p></td><td><p>Học THPT</p></td><td><p>Trường THPT Tô Hiến Thành</p></td><td><p>344 Lê Lai, Đông Sơn, Thanh Hóa</p></td></tr><tr><td><p>2023</p></td><td><p>2025</p></td><td><p>Học cao đẳng</p></td><td><p>Trường cao đẳng FPT Polytechnic Thanh Hóa</p></td><td><p>Beta, Tổ hợp giáo dục FPT, Đại lộ Võ Nguyên Giáp, phường Quảng Thành, Thành phố Thanh Hóa</p></td></tr><tr><td><p>05/2025</p></td><td><p>Đến nay</p></td><td><p>Làm việc tại ThinkLabs</p></td><td><p>Cty cổ phần ThinkLabs</p></td><td><p>Tầng 5 - Nhà Sách Lê Lợi, Số 51 Đại Lộ Lê Lợi, Phường Tân Sơn, Thành Phố Thanh Hóa</p></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td><td></td><td></td></tr></table><p>HOÀN CẢNH GIA ĐÌNH</p><p>Họ và tên bố: Nguyễn Viết Mong        Tuổi 43         Nghề nghiệp: Lao động tự do</p><p>Trước cách mạng Tháng 8 làm gì? Ở đâu? </p><p>Chưa sinh ra</p><p>	</p><p>	 </p><p>Trong kháng chiến chống thực dân Pháp làm gì? Ở đâu? <br />Chưa sinh ra</p><p>	</p><p>	</p><p>Từ năm 1955 đến nay làm gì? Ở đâu? (Ghi rõ tên cơ quan, xí nghiệp hiện nay đang làm) </p><p>Làm ở công ty TNHH Việt Nhật ở Thanh Hóa</p><p>	</p><p>Họ và tên mẹ: Vũ Thị Chung       Tuổi: 42        Nghề nghiệp: Lao động tự do</p><p>Trước cách mạng Tháng 8 làm gì? Ở đâu? </p><p>Chưa sinh ra</p><p>	</p><p>	</p><p>Trong kháng chiến chống thực dân Pháp làm gì? Ở đâu? </p><p>Chưa sinh ra</p><p>	</p><p>	</p><p>Từ năm 1955 đến nay làm gì? Ở đâu? (Ghi rõ tên cơ quan, xí nghiệp hiện nay đang làm)<br />Làm ở công ty TNHH Việt Nhật ở Thanh Hóa</p><p>	</p><p>	</p><p>	</p><p><strong>HỌ VÀ TÊN ANH CHỊ EM RUỘT</strong></p><p><strong><em>(Ghi rõ tên, tuổi, chỗ ở, nghề nghiệp và trình độ chính trị của từng người)</em></strong></p><p>Họ và tên (em): Nguyễn Mai Khánh.	</p><p>Tuổi:  15	</p><p>Nơi cư trú: Phố Hưng Thuận, phường Quảng Phú, Thành phố Thanh Hóa</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>	</p><p>Họ và tên vợ hoặc chồng: Không có             Tuổi:Không	</p><p>Nghề nghiệp: Không	</p><p>Nơi làm việc: Không	</p><p>Chỗ ở hiện nay:	</p><p>Họ và tên các con:</p><p>1) ................................................. Tuổi: ............ Nghề nghiệp: 	</p><p>2) ................................................. Tuổi: ............ Nghề nghiệp: 	</p><p>3) ................................................. Tuổi: ............ Nghề nghiệp: 	</p><p>4) ................................................. Tuổi: ............ Nghề nghiệp: 	</p><p>5) ................................................. Tuổi: ............ Nghề nghiệp: 	</p><h3>KHEN THƯỞNG VÀ KỶ LUẬT</h3><p>Khen thưởng: 	</p><p>Kỷ luật: 	</p><h3>TỰ NHẬN XÉT BẢN THÂN</h3><p>Về chấp hành pháp luật, nội quy, quy chế của đơn vị và nơi ở: Rất tốt</p><p>	</p><p>Sức khỏe: Tốt	</p><p>Có đủ điều kiện dự thi không: Đủ	</p><h3>LỜI CAM ĐOAN</h3><ol><li>Tôi xin cam đoan những lời khai trên là đúng sự thật, nếu có điều gì sai trái, tôi xin tự thôi học và chịu trách nhiệm trước pháp luật.</li><li>Được dự tuyển tôi tự nguyện thực hiện đúng và đầy đủ nội quy, quy chế tuyển sinh và đào tạo của Bộ Giáo dục và Đào tạo và của Học viện.</li></ol><p><em>						                                    Thanh Hóa ngày 09tháng 12 năm 2025</em></p><p><em>   </em><strong> </strong><em>	                                     					    </em><strong>Người khai ký tên</strong></p><h3>XÁC NHẬN CỦA THỦ TRƯỞNG CƠ QUAN  ( HOẶC CHỦ TỊCH UBND PHƯỜNG, XÃ) QUẢN LÝ NGƯỜI DỰ TUYỂN</h3><p>Đơn vị xác nhận hồ sơ của anh, chị khai như trên là đúng với hồ sơ mà cơ quan (phường, xã) đang quản lý.</p><p><em>......,ngày……tháng……năm……</em></p><p><em>   </em><strong> </strong><em>	                                     			                </em><strong>Họ và tên, chữ ký, đóng dấu </strong></p>', '/uploads/classroom-tests/1773558774100-af5tftr6c2j-1.0_M_u_Phi_u_tuy_n_sinh_PTIT_2025.docx', NULL, 10, 1, 'cmmq82ca20000t4pno5i1wqhl', '2026-03-15 07:12:54.297', '2026-03-15 07:12:54.297');

