INSERT IGNORE INTO `Exercise` (`id`, `lessonId`, `type`, `title`, `question`, `answer`, `difficulty`, `points`, `sortOrder`, `answerVisible`, `dueDate`, `createdAt`, `updatedAt`) VALUES
('cmmqlh3tx000b6utndw3r0he8', 'cmmql64qg00016utn3yrlag26', 'practice', 'Tạo List và Truy xuất cơ bản', '<p>Tạo một list t&ecirc;n l&agrave; <code>my_tools</code> chứa 5 ng&ocirc;n ngữ lập tr&igrave;nh hoặc c&ocirc;ng cụ bạn y&ecirc;u th&iacute;ch nhất. In ra phần tử thứ 3 v&agrave; phần tử cuối c&ugrave;ng của list đ&oacute;.</p>', 'my_tools = [\"Python\", \"JavaScript\", \"SQL\", \"Git\", \"Docker\"]\nprint(my_tools[2]) # Phần tử thứ 3 (index 2)\nprint(my_tools[-1]) # Phần tử cuối cùng', 'easy', 10, 0, 1, NULL, '2026-03-14 17:23:32.133', '2026-03-14 17:23:32.133'),
('cmmqlh3tx000c6utn5bsz7d62', 'cmmql64qg00016utn3yrlag26', 'practice', 'Slicing với List ngày', '<p>Cho một list <code>days = [\"Thứ 2\", \"Thứ 3\", \"Thứ 4\", \"Thứ 5\", \"Thứ 6\", \"Thứ 7\", \"Chủ nhật\"]</code>. H&atilde;y d&ugrave;ng kỹ thuật Slicing để in ra:</p><ol><li>Chỉ c&aacute;c ng&agrave;y cuối tuần.</li><li>Chỉ c&aacute;c ng&agrave;y trong tuần (từ Thứ 2 đến Thứ 6).</li></ol>', 'days = [\"Thứ 2\", \"Thứ 3\", \"Thứ 4\", \"Thứ 5\", \"Thứ 6\", \"Thứ 7\", \"Chủ nhật\"]\n# Các ngày cuối tuần\nprint(days[5:])\n# Các ngày trong tuần\nprint(days[:5])', 'intermediate', 15, 1, 1, NULL, '2026-03-14 17:23:32.133', '2026-03-14 17:23:32.133'),
('cmmqlh3tx000d6utnkr2p1521', 'cmmql64qg00016utn3yrlag26', 'practice', 'Truy xuất phần tử trong List lồng nhau', '<p>Bạn có; list <code>A = [1, 2, [3, 4], 5]</code>. L&agrave;m thế n&agrave;o để d&ugrave;ng Index in ra được số <code>4</code>?</p>', 'A = [1, 2, [3, 4], 5]\nprint(A[2][1])', 'intermediate', 20, 2, 1, NULL, '2026-03-14 17:23:32.133', '2026-03-14 17:23:32.133'),
('cmmr9hki4000z6utnf4tn3dkt', 'cmmr9hki4000v6utnqxt2tvcr', 'practice', 'Quản lý Người Dùng trong Nhóm Dự Án', '<p>H&atilde;y vận dụng kiến thức vừa học để giải quyết b&agrave;i to&aacute;n quản l&yacute; người d&ugrave;ng sau đ&acirc;y:</p><p><strong>Đề b&agrave;i:</strong> Bạn đang quản l&yacute; danh s&aacute;ch t&agrave;i khoản của một nh&oacute;m dự &aacute;n: <code>team = [\"admin\", \"editor\", \"guest\"]</code></p><ol><li><p>Người d&ugrave;ng <code>\"guest\"</code> vừa được thăng cấp, h&atilde;y cập nhật gi&aacute; trị <code>\"guest\"</code> th&agrave;nh <code>\"moderator\"</code>.</p></li><li><p>Một th&agrave;nh vi&ecirc;n mới t&ecirc;n <code>\"developer\"</code> vừa gia nhập, h&atilde;y th&ecirc;m người n&agrave;y v&agrave;o <strong>cuối</strong> danh s&aacute;ch.</p></li><li><p>Vị tr&iacute; <code>\"editor\"</code> kh&ocirc;ng c&ograve;n cần thiết nữa, h&atilde;y x&oacute;a n&oacute; khỏi danh s&aacute;ch.</p></li><li><p>In danh s&aacute;ch cuối c&ugrave;ng ra m&agrave;n h&igrave;nh.</p></li></ol>', 'team = [\"admin\", \"editor\", \"guest\"]\n\n# 1. Cập nhật \"guest\" thành \"moderator\"\ntry:\n    guest_index = team.index(\"guest\")\n    team[guest_index] = \"moderator\"\nexcept ValueError:\n    print(\"Không tìm thấy \'guest\' trong danh sách.\")\n\n# 2. Thêm \"developer\" vào cuối danh sách\nteam.append(\"developer\")\n\n# 3. Xóa \"editor\" khỏi danh sách\ntry:\n    team.remove(\"editor\")\nexcept ValueError:\n    print(\"Không tìm thấy \'editor\' trong danh sách.\")\n\n# 4. In danh sách cuối cùng\nprint(team)\n# Expected Output: [\'admin\', \'moderator\', \'developer\']', 'easy', 10, 0, 1, NULL, '2026-03-15 04:35:44.524', '2026-03-15 04:35:44.524'),
('cmmralrcl00156utnz4k2vke7', 'cmmralrck00116utn4i77xgvh', 'practice', 'Thử thách Tuple Immutable', '<p>Khởi tạo một Tuple chứa c&aacute;c đu&ocirc;i file h&igrave;nh ảnh hợp lệ: <div class=\"code-block\">(\"jpg\", \"png\", \"gif\")</div>. Thử d&ugrave;ng code để đổi <div class=\"code-block\">\"gif\"</div> th&agrave;nh <div class=\"code-block\">\"svg\"</div> xem Python sẽ mắng bạn như thế n&agrave;o nh&eacute;!</p>', 'image_extensions = (\"jpg\", \"png\", \"gif\")\nprint(\"Tuple ban đầu:\", image_extensions)\n# Thử thay đổi phần tử thứ 2 (chữ \'gif\') thành \'svg\'\n# image_extensions[2] = \"svg\" # Dòng này sẽ gây lỗi TypeError\n# print(\"Sau khi cố gắng thay đổi:\", image_extensions)\nprint(\"Khi chạy dòng \'image_extensions[2] = \\\"svg\\\"\', Python sẽ báo lỗi TypeError vì Tuple là immutable.\")', 'easy', 10, 0, 1, NULL, '2026-03-15 05:06:59.636', '2026-03-15 05:06:59.636'),
('cmmralrcl00166utnwjk5g5ay', 'cmmralrck00116utn4i77xgvh', 'practice', 'Xử lý phản hồi API giả định', '<p>Tạo một Dictionary t&ecirc;n l&agrave; <div class=\"code-block\">my_api_response</div> m&ocirc; phỏng một phản hồi từ server, gồm c&aacute;c key:</p><ol><li><div class=\"code-block\">status_code</div> (gi&aacute; trị l&agrave; 200)</li><li><div class=\"code-block\">message</div> (gi&aacute; trị l&agrave; \"Kết nối th&agrave;nh c&ocirc;ng\")</li><li><div class=\"code-block\">data</div> (gi&aacute; trị l&agrave; một List chứa 2 t&ecirc;n người d&ugrave;ng bất kỳ).</li></ol><p>Sau đ&oacute;, h&atilde;y viết lệnh để chỉ in ra t&ecirc;n của người d&ugrave;ng thứ nhất nằm trong key <div class=\"code-block\">data</div>.</p>', 'my_api_response = {\n    \"status_code\": 200,\n    \"message\": \"Kết nối thành công\",\n    \"data\": [\"Alice\", \"Bob\"]\n}\n# In ra tên người dùng thứ nhất\nfirst_user = my_api_response[\"data\"][0]\nprint(\"Người dùng thứ nhất:\", first_user)\n# Expected output: Người dùng thứ nhất: Alice', 'easy', 15, 1, 1, NULL, '2026-03-15 05:06:59.636', '2026-03-15 05:06:59.636'),
('cmmrc071h001b6utns0y04ehq', 'cmmrc071h00186utnqblnr73q', 'practice', 'Lọc email duy nhất', '<p>Bạn đang cào (crawl) dữ liệu email từ một trang web và thu được một List chứa rất nhiều email trùng nhau:</p><div class=\"code-block\">emails = [\"a@gmail.com\", \"b@gmail.com\", \"a@gmail.com\", \"c@gmail.com\"]</div><p>Hãy dùng 1 dòng code để biến nó thành một danh sách (List) chỉ chứa các email duy nhất.</p>', 'list(set(emails))', 'easy', 10, 0, 1, NULL, '2026-03-15 05:46:12.773', '2026-03-15 05:46:12.773'),
('cmmrc071h001c6utnrhe5o0jz', 'cmmrc071h00186utnqblnr73q', 'practice', 'Tìm kỹ năng chung giữa ứng viên và dự án', '<p>Bạn có danh sách kỹ năng yêu cầu của dự án: <div class=\"code-block\">req_skills = {\"Python\", \"Git\", \"SQL\", \"Linux\"}</div> Và kỹ năng của ứng viên: <div class=\"code-block\">candidate_skills = {\"Python\", \"HTML\", \"CSS\", \"Git\"}</div></p><p>Hãy dùng phép toán của Set để in ra những kỹ năng mà ứng viên <strong>đã đáp ứng được</strong> cho dự án.</p>', 'req_skills & candidate_skills', 'medium', 15, 1, 1, NULL, '2026-03-15 05:46:12.773', '2026-03-15 05:46:12.773');

