INSERT IGNORE INTO `Lesson` (`id`, `chapterId`, `title`, `slug`, `content`, `duration`, `difficulty`, `sortOrder`, `isLocked`, `isPublished`, `objectiveKnowledge`, `objectiveSkills`, `objectiveAttitude`, `createdAt`, `updatedAt`) VALUES
('cmmql64qg00016utn3yrlag26', 'chapter-1', 'List trong Python: Khái niệm, Tạo và Truy xuất', NULL, NULL, 75, 'beginner', 2, 0, 1, 'Hiểu được khái niệm, đặc điểm của List trong Python và các cách tạo List khác nhau.', 'Thực hiện truy xuất phần tử đơn lẻ (indexing) và lấy một nhóm phần tử (slicing) từ List.', 'Nhận thức được tầm quan trọng của List như một cấu trúc dữ liệu cơ bản trong lập trình thực tế và các lĩnh vực nâng cao như AI.', '2026-03-14 17:15:00.086', '2026-03-14 17:23:32.133'),
('cmmr9hki4000v6utnqxt2tvcr', 'chapter-1', 'List trong Python: Thêm, Xóa và Cập Nhật Phần Tử', NULL, NULL, 75, 'beginner', 3, 0, 1, 'Hiểu được tính chất mutable (có thể thay đổi) của List trong Python và nắm vững các phương thức cơ bản để thêm, xóa, cập nhật phần tử.', 'Thực hiện thành thạo các thao tác thêm (append, insert, extend), xóa (remove, pop, del, clear) và cập nhật phần tử trong List bằng code Python.', 'Nắm được tầm quan trọng của hiệu suất khi thao tác với List lớn và biết cách áp dụng các phương pháp tối ưu trong thực tế.', '2026-03-15 04:35:44.524', '2026-03-15 04:35:44.524'),
('cmmralrck00116utn4i77xgvh', 'chapter-1', 'Tuple và Dictionary: Cấu trúc dữ liệu có tổ chức và an toàn', NULL, NULL, 75, 'intermediate', 4, 0, 1, 'Nắm vững khái niệm, cú pháp và đặc điểm của Tuple và Dictionary, hiểu sự khác biệt giữa chúng với List.', 'Thực hiện tạo, truy xuất, thêm, sửa, xóa dữ liệu trong Tuple và Dictionary, và biết khi nào nên sử dụng từng loại cấu trúc.', 'Phát triển tư duy lựa chọn cấu trúc dữ liệu phù hợp để viết code an toàn, hiệu quả và có tổ chức hơn.', '2026-03-15 05:06:59.636', '2026-03-15 05:06:59.636'),
('cmmrc071h00186utnqblnr73q', 'chapter-1', 'Set trong Python và Ôn tập Cấu trúc Dữ liệu', NULL, NULL, 75, 'intermediate', 5, 0, 1, 'Hiểu rõ khái niệm, 3 đặc điểm cốt lõi (không thứ tự, duy nhất, có thể thay đổi) và cú pháp của Set. Nắm vững cách Set khác biệt và bổ trợ cho List, Tuple, Dictionary. Biết các phép toán tập hợp cơ bản.', 'Thực hiện thành thạo việc tạo, thêm, xóa phần tử trong Set. Áp dụng các phép toán giao, hợp, hiệu để so sánh dữ liệu giữa các Set. Lựa chọn cấu trúc dữ liệu tối ưu (List, Tuple, Dictionary, Set) cho các bài toán thực tế như lọc trùng lặp và tìm kiếm nhanh.', 'Phát triển tư duy phân tích để lựa chọn cấu trúc dữ liệu phù hợp, giúp giải quyết các vấn đề liên quan đến dữ liệu duy nhất và hiệu suất tìm kiếm một cách hiệu quả.', '2026-03-15 05:46:12.773', '2026-03-15 05:46:12.773');

