INSERT IGNORE INTO `Section` (`id`, `lessonId`, `title`, `content`, `sortOrder`, `createdAt`, `updatedAt`) VALUES
('cmmqlh3tx00086utnu319yeoj', 'cmmql64qg00016utn3yrlag26', 'Khái niệm List trong Python', '<h2>1. Kh&aacute;i niệm: List l&agrave; g&igrave;?</h2><p>Trong thế giới thực, bạn c&oacute; danh s&aacute;ch lớp, danh s&aacute;ch việc cần l&agrave;m, hay danh s&aacute;ch m&oacute;n ăn. Trong Python, <strong>List</strong> (danh s&aacute;ch) cũng tương tự. N&oacute; l&agrave; một cấu tr&uacute;c dữ liệu d&ugrave;ng để lưu trữ một bộ (collection) gồm nhiều gi&aacute; trị kh&aacute;c nhau, được sắp xếp theo một thứ tự nhất định.</p><p><strong>Đặc điểm cốt l&otilde;i của List trong Python:</strong></p><ul><li><p><strong>C&oacute; thứ tự (Ordered):</strong> Mỗi phần tử c&oacute; một vị tr&iacute; cố định.</p></li><li><p><strong>C&oacute; thể thay đổi (Mutable):</strong> Bạn c&oacute; thể sửa, th&ecirc;m, x&oacute;a phần tử sau khi đ&atilde; tạo (ch&uacute;ng ta sẽ học ở B&agrave;i 2).</p></li><li><p><strong>Chứa được mọi thứ (Heterogeneous):</strong> Một list c&ó; thể chứa số, chuỗi, boolean, thậm ch&iacute; chứa cả một list kh&aacute;c b&ecirc;n trong n&oacute;.</p></li></ul><blockquote><p><strong>💡 Tưởng tượng:</strong> H&atilde;y coi List như một đo&agrave;n t&agrave;u hỏa. Mỗi toa t&agrave;u (phần tử) c&ó; một số thứ tự, v&agrave; trong mỗi toa c&oacute; thể chở bất cứ thứ g&igrave; (h&agrave;nh kh&aacute;ch, than, h&agrave;ng h&oacute;a...).</p></blockquote>', 0, '2026-03-14 17:23:32.133', '2026-03-14 17:23:32.133'),
('cmmqlh3tx00096utn2h8ed9e4', 'cmmql64qg00016utn3yrlag26', 'Cách Tạo List', '<h2>2. C&aacute;ch Tạo List</h2><p>Để tạo một list, bạn chỉ cần đặt c&aacute;c phần tử v&agrave;o trong cặp ngoặc vu&ocirc;ng <code>[]</code>, c&aacute;ch nhau bởi dấu phẩy <code>,</code>.</p><div class=\"code-block\">\n# 1. Tạo một List rỗng (chưa c&oacute; g&igrave; cả)\nempty_list = []\n# Hoặc d&ugrave;ng h&agrave;m list()\nempty_list_2 = list()\n\n# 2. List chứa c&aacute;c con số (rất hay d&ugrave;ng khi xử l&yacute; dữ liệu)\nscores = [8.5, 9.0, 7.5, 10.0]\n\n# 3. List chứa chuỗi (String)\nframeworks = [\"Laravel\", \"Django\", \"Flask\"]\n\n# 4. List hỗn hợp (Chứa nhiều kiểu dữ liệu kh&aacute;c nhau)\nstudent_info = [\"Nguyễn Văn A\", 20, True, 8.5]\n\n# 5. List lồng List (Nested List - Ma trận)\nmatrix = [\n    [1, 2, 3],\n    [4, 5, 6],\n    [7, 8, 9]\n]\n</div>', 1, '2026-03-14 17:23:32.133', '2026-03-14 17:23:32.133'),
('cmmqlh3tx000a6utnbbq2c6q6', 'cmmql64qg00016utn3yrlag26', 'Truy Xuất Phần Tử và Ứng Dụng', '<h2>3. Truy Xuất Phần Tử (Lấy dữ liệu ra khỏi List)</h2><p>Đ&acirc;y l&agrave; kỹ năng bạn sẽ d&ugrave;ng h&agrave;ng ng&agrave;y. Python sử dụng <strong>Index (Chỉ số)</strong> để x&aacute;c định vị tr&iacute; phần tử. <strong>QUAN TRỌNG:</strong> Trong lập tr&igrave;nh, chỉ số lu&ocirc;n bắt đầu từ số <strong>0</strong>, kh&ocirc;ng phải 1.</p><h2>a. Indexing (Truy xuất đơn lẻ)</h2><ul><li><p><strong>Chỉ số dương (Từ tr&aacute;i sang phải):</strong> Bắt đầu từ <code>0, 1, 2...</code></p></li><li><p><strong>Chỉ số &acirc;m (Từ phải sang tr&aacute;i):</strong> Bắt đầu từ <code>-1, -2, -3...</code> (rất tiện khi muốn lấy phần tử cuối c&ugrave;ng m&agrave; kh&ocirc;ng cần biết list d&agrave;i bao nhi&ecirc;u).</p></li></ul><div class=\"code-block\">\ntech_stack = [\"HTML\", \"CSS\", \"JavaScript\", \"PHP\", \"Python\"]\n\nprint(tech_stack[0])   # Output: HTML (Phần tử đầu ti&ecirc;n)\nprint(tech_stack[2])   # Output: JavaScript (Phần tử thứ 3)\n\nprint(tech_stack[-1])  # Output: Python (Phần tử cuối c&ugrave;ng)\nprint(tech_stack[-2])  # Output: PHP (Phần tử &aacute;p ch&oacute;t)\n</div><h2>b. Slicing (Cắt L&aacute;t - Lấy một nh&oacute;m phần tử)</h2><p>C&uacute; ph&aacute;p: <code>t&ecirc;n_list[start : stop : step]</code></p><ul><li><p><code>start</code>: Vị tr&iacute; bắt đầu (Bao gồm vị tr&iacute; n&agrave;y).</p></li><li><p><code>stop</code>: Vị tr&iacute; kết th&uacute;c (<strong>KH&Ocirc;NG</strong> bao gồm vị tr&iacute; n&agrave;y).</p></li><li><p><code>step</code>: Bước nhảy (Mặc định l&agrave; 1).</p></li></ul><div class=\"code-block\">\nnumbers = [10, 20, 30, 40, 50, 60, 70]\n\n# Lấy từ index 1 đến index 3 (kh&ocirc;ng lấy index 4)\nprint(numbers[1:4])    # Output: [20, 30, 40]\n\n# Lấy từ đầu đến index 2\nprint(numbers[:3])     # Output: [10, 20, 30]\n\n# Lấy từ index 3 đến cuối\nprint(numbers[3:])     # Output: [40, 50, 60, 70]\n\n# Bước nhảy: Lấy c&aacute;c phần tử c&aacute;ch nhau 2 vị tr&iacute;\nprint(numbers[0:6:2])  # Output: [10, 30, 50]\n\n# Mẹo: Đảo ngược list bằng slicing\nprint(numbers[::-1])   # Output: [70, 60, 50, 40, 30, 20, 10]\n</div><h2>4. Kiến Thức Thực Tế (G&oacute;c nh&igrave;n chuy&ecirc;n gia)</h2><p>Tại sao List lại quan trọng đến vậy?</p><ul><li><p><strong>Trong Web Development:</strong> Khi bạn truy vấn dữ liệu từ Database (v&iacute; dụ như lấy danh s&aacute;ch b&agrave;i viết để l&agrave;m bảng tin - Newsfeed), kết quả trả về thường được xử l&yacute; dưới dạng List chứa c&aacute;c đối tượng (Object/Dictionary) trước khi render ra HTML.</p></li><li><p><strong>Trong Tr&iacute; Tuệ Nh&acirc;n Tạo (AI):</strong> List l&agrave; tiền đề để hiểu về Vector v&agrave; Ma trận. C&aacute;c thư viện xử l&yacute; dữ liệu khổng lồ như NumPy (thường d&ugrave;ng trong Machine Learning) đều x&acirc;y dựng mảng (Array) dựa tr&ecirc;n tư duy cấu tr&uacute;c của List trong Python nhưng được tối ưu h&oacute;a về tốc độ. Hiểu r&otilde; Indexing v&agrave; Slicing b&acirc;y giờ, sau n&agrave;y bạn thao t&aacute;c với dữ liệu AI sẽ nh&agrave;n hơn rất nhiều.</p></li></ul><h2>5. Tổng Kết</h2><ul><li><p>List d&ugrave;ng để lưu trữ nhiều gi&aacute; trị, đặt trong <code>[]</code>.</p></li><li><p>Index (chỉ số) lu&ocirc;n bắt đầu từ <strong>0</strong>.</p></li><li><p>Index &acirc;m gi&uacute;p truy xuất từ cuối list ngược l&ecirc;n (<code>-1</code> l&agrave; phần tử cuối).</p></li><li><p>C&uacute; ph&aacute;p Slicing <code>[start:stop:step]</code> gi&uacute;p \"cắt\" một mảng dữ liệu con một c&aacute;ch nhanh ch&oacute;ng.</p></li></ul><hr>', 2, '2026-03-14 17:23:32.133', '2026-03-14 17:23:32.133'),
('cmmr9hki4000w6utn6qezsn6p', 'cmmr9hki4000v6utnqxt2tvcr', 'Cập Nhật (Sửa) Phần Tử', '<p>Để thay đổi gi&aacute; trị của một phần tử đ&atilde; c&oacute; sẵn trong List, bạn chỉ cần gọi đ&uacute;ng Index (chỉ số) của n&oacute; v&agrave; g&aacute;n cho n&oacute; một gi&aacute; trị mới bằng dấu <code>=</code>.</p><div class=\"code-block\"><pre><code># Giả sử đ&acirc;y l&agrave; danh s&aacute;ch điểm số của một sinh vi&ecirc;n\nscores = [7.0, 8.5, 6.0, 9.0]\n\n# Sinh vi&ecirc;n ph&uacute;c khảo v&agrave; được tăng điểm b&agrave;i thi thứ 3 (index 2)\nscores[2] = 7.5  \n\nprint(scores) \n# Output: [7.0, 8.5, 7.5, 9.0]</code></pre></div><p><em>Lưu &yacute:</em> Bạn cũng c&oacute; thể d&ugrave;ng Slicing để cập nhật nhiều phần tử c&ugrave;ng l&uacute;c, nhưng h&atilde;y chắc chắn độ d&agrave;i của dữ liệu mới tương th&iacute;ch với khoảng bạn muốn cắt.</p>', 0, '2026-03-15 04:35:44.524', '2026-03-15 04:35:44.524'),
('cmmr9hki4000x6utnua1pkkfr', 'cmmr9hki4000v6utnqxt2tvcr', 'Thêm Phần Tử Mới', '<p>C&oacute; 3 phương thức phổ biến nhất để \"nhồi\" th&ecirc;m dữ liệu v&agrave;o List. T&ugrave;y v&agrave;o mục đ&iacute;ch m&agrave; ch&uacute;ng ta chọn c&ocirc;ng cụ ph&ugrave; hợp.</p><h3><code>append(gi&aacute; trị)</code>: Th&ecirc;m v&agrave;o cuối List</h3><p>Đ&acirc;y l&agrave; phương thức được d&ugrave;ng nhiều nhất. N&oacute; nh&eacute;t th&ecirc;m 1 phần tử duy nhất v&agrave;o vị tr&iacute; cuối c&ugrave;ng của danh s&aacute;ch.</p><div class=\"code-block\"><pre><code># Danh s&aacute;ch c&aacute;c b&agrave;i tập sinh vi&ecirc;n đ&atilde; nộp\nsubmitted_assignments = [\"B&agrave;i 1\", \"B&agrave;i 2\"]\n\n# Sinh vi&ecirc;n vừa nộp th&ecirc;m b&agrave;i 3\nsubmitted_assignments.append(\"B&agrave;i 3\")\n\nprint(submitted_assignments) \n# Output: [\'B&agrave;i 1\', \'B&agrave;i 2\', \'B&agrave;i 3\']</code></pre></div><h3><code>insert(index, gi&aacute; trị)</code>: Ch&egrave;n v&agrave;o vị tr&iacute; bất kỳ</h3><p>Nếu bạn muốn phần tử mới nằm ở một vị tr&iacute; cụ thể (v&iacute; dụ: ghim một b&agrave;i viết l&ecirc;n đầu bảng tin), h&atilde;y d&ugrave;ng <code>insert</code>. C&aacute;c phần tử ph&iacute;a sau sẽ tự động l&ugrave;i lại một bước.</p><div class=\"code-block\"><pre><code>newsfeed = [\"Post 2\", \"Post 3\"]\n\n# Ghim \"Post 1\" l&ecirc;n đầu ti&ecirc;n (index 0)\nnewsfeed.insert(0, \"Post 1\")\n\nprint(newsfeed) \n# Output: [\'Post 1\', \'Post 2\', \'Post 3\']</code></pre></div><h3><code>extend(list_kh&aacute;c)</code>: Gh&eacute;p nối List</h3><p>Khi bạn c&oacute; một danh s&aacute;ch mới v&agrave; muốn gộp to&agrave;n bộ phần tử của n&oacute; v&agrave;o danh s&aacute;ch cũ (giống như t&iacute;nh năng \"Tải th&ecirc;m b&agrave;i viết cũ\" tr&ecirc;n web).</p><div class=\"code-block\"><pre><code>current_users = [\"Alice\", \"Bob\"]\nnew_users = [\"Charlie\", \"David\"]\n\ncurrent_users.extend(new_users)\n\nprint(current_users) \n# Output: [\'Alice\', \'Bob\', \'Charlie\', \'David\']</code></pre></div>', 1, '2026-03-15 04:35:44.524', '2026-03-15 04:35:44.524'),
('cmmr9hki4000y6utnju66ps7v', 'cmmr9hki4000v6utnqxt2tvcr', 'Xóa Phần Tử & Lời Khuyên Chuyên Gia', '<p>Tương tự như th&ecirc;m, Python cung cấp nhiều \"vũ kh&iacute;\" để dọn dẹp dữ liệu thừa.</p><h3><code>remove(gi&aacute; trị)</code>: X&oacute;a theo T&ecirc;n/Gi&aacute; trị</h3><p>X&oacute;a phần tử đầu ti&ecirc;n trong List c&oacute; gi&aacute; trị khớp với tham số truyền v&agrave;o. Nếu gi&aacute; trị kh&ocirc;ng tồn tại, chương tr&igrave;nh sẽ b&aacute;o lỗi.</p><div class=\"code-block\"><pre><code>tech_stack = [\"HTML\", \"CSS\", \"jQuery\", \"JavaScript\", \"PHP\"]\n\n# C&ocirc;ng nghệ cũ, cần loại bỏ khỏi dự &aacute;n\ntech_stack.remove(\"jQuery\")\n\nprint(tech_stack) \n# Output: [\'HTML\', \'CSS\', \'JavaScript\', \'PHP\']</code></pre></div><h3><code>pop(index)</code>: X&oacute;a theo Vị tr&iacute; v&agrave; Lấy ra sử dụng</h3><p><code>pop()</code> cực kỳ th&uacute; vị v&igrave; n&oacute; vừa x&oacute;a phần tử khỏi List, lại vừa \"trả về\" phần tử đ&oacute; để bạn c&oacute; thể lưu v&agrave;o một biến kh&aacute;c. Nếu kh&ocirc;ng truyền <code>index</code>, n&oacute; mặc định x&oacute;a phần tử <strong>cuối c&ugrave;ng</strong>.</p><div class=\"code-block\"><pre><code>tasks = [\"Viết code\", \"Sửa lỗi 503\", \"Deploy VPS\"]\n\n# X&oacute;a task cuối c&ugrave;ng (đ&atilde; l&agrave;m xong)\ncompleted_task = tasks.pop()\n\nprint(\"Task vừa ho&agrave;n th&agrave;nh:\", completed_task) # Output: Deploy VPS\nprint(\"Task c&ograve;n lại:\", tasks)                 # Output: [\'Viết code\', \'Sửa lỗi 503\']</code></pre></div><h3><code>del</code> v&agrave; <code>clear()</code></h3><ul><li><p><code>del list_name[index]</code>: Từ kh&oacute;a x&oacute;a phần tử tại một vị tr&iacute; hoặc một khoảng (slicing) khỏi bộ nhớ.</p></li><li><p><code>list_name.clear()</code>: X&oacute;a sạch s&agrave;nh sanh mọi thứ trong List, trả về List rỗng <code>[]</code>.</p></li></ul><h2>Kiến Thức Thực Tế (G&oacute;c nh&igrave;n chuy&ecirc;n gia)</h2><p>Khi bạn bắt tay v&agrave;o l&agrave;m c&aacute;c ứng dụng web thực tế (như l&agrave;m một nền tảng nộp b&agrave;i tập, một trang viết nhật k&yacute; c&aacute; nh&acirc;n hay xử l&yacute; backend API), hiệu suất (Performance) l&agrave; thứ phải đặt l&ecirc;n h&agrave;ng đầu.</p><p>Trong khoa học m&aacute;y t&iacute;nh, c&oacute; một kh&aacute;i niệm gọi l&agrave; Độ phức tạp thuật to&aacute;n (Big O Notation).</p><ul><li><p>Khi bạn d&ugrave;ng <code>append()</code> để th&ecirc;m dữ liệu v&agrave;o cuối List, Python thực hiện rất nhanh, độ phức tạp l&agrave; <span class=\"base\"><span class=\"mord mathnormal\">O</span><span class=\"mopen\">(</span><span class=\"mord\">1</span><span class=\"mclose\">)</span></span>.</p></li><li><p>Nhưng nếu bạn d&ugrave;ng <code>insert(0, gi&aacute; trị)</code> để ch&egrave;n v&agrave;o đầu List, Python phải dịch chuyển to&agrave;n bộ h&agrave;ng ng&agrave;n phần tử ph&iacute;a sau l&ugrave;i lại một &ocirc;. Độ phức tạp l&uacute;c n&agrave;y l&agrave; <span class=\"base\"><span class=\"mord mathnormal\">O</span><span class=\"mopen\">(</span><span class=\"mord mathnormal\">n</span><span class=\"mclose\">)</span></span> (n l&agrave; số phần tử). Nếu List của bạn chứa h&agrave;ng triệu bản ghi nhật k&yacute;, thao t&aacute;c n&agrave;y sẽ l&agrave;m server của bạn bị chậm đi đ&aacute;ng kể.</p></li></ul><p><strong>Lời khuy&ecirc;n:</strong> H&atilde;y ưu ti&ecirc;n d&ugrave;ng <code>append()</code> v&agrave; <code>pop()</code> (kh&ocirc;ng truyền tham số) để hệ thống chạy mượt m&agrave; nhất c&oacute; thể nh&eacute;.</p><h2>Tổng Kết</h2><ul><li><p><strong>Sửa:</strong> <code>list[index] = gi&aacute;_trị_mới</code></p></li><li><p><strong>Th&ecirc;m:</strong> <code>append()</code> (cuối), <code>insert()</code> (vị tr&iacute; bất kỳ), <code>extend()</code> (gộp list).</p></li><li><p><strong>X&oacute;a:</strong> <code>remove()</code> (theo gi&aacute; trị), <code>pop()</code> (theo vị tr&iacute; &amp; lấy ra), <code>del</code> (x&oacute;a theo index/slicing), <code>clear()</code> (x&oacute;a sạch).</p></li></ul>', 2, '2026-03-15 04:35:44.524', '2026-03-15 04:35:44.524'),
('cmmralrcl00126utnl9psaw38', 'cmmralrck00116utn4i77xgvh', 'Giới thiệu chung và Tuple', '<p>Ở hai b&agrave;i trước, ch&uacute;ng ta đ&atilde; \"c&agrave;y n&aacute;t\" List rồi. List rất mạnh mẽ v&agrave; linh hoạt, nhưng trong thế giới lập tr&igrave;nh, kh&ocirc;ng phải l&uacute;c n&agrave;o linh hoạt cũng tốt. C&oacute; những dữ liệu ch&uacute;ng ta cần \"đ&oacute;ng băng\" lại để bảo vệ, hoặc cần g&aacute;n nh&atilde;n r&otilde; r&agrave;ng để dễ t&igrave;m kiếm thay v&igrave; phải nhớ từng con số index kh&ocirc; khan.</p><p>H&ocirc;m nay, với tư c&aacute;ch l&agrave; một người từng dọn dẹp kh&ocirc;ng &iacute;t những đoạn code lộn xộn, m&igrave;nh sẽ giới thiệu cho bạn hai cấu tr&uacute;c dữ liệu cực kỳ quan trọng gi&uacute;p code của bạn an to&agrave;n v&agrave; c&oacute; tổ chức hơn: <strong>Tuple</strong> v&agrave; <strong>Dictionary</strong>.</p><h2>1. Tuple - Phi&ecirc;n bản \"Chỉ đọc\" của List</h2><p><strong>Kh&aacute;i niệm:</strong> Tuple giống hệt List về mặt lưu trữ (c&oacute; thứ tự, chứa được nhiều kiểu dữ liệu), nhưng c&ó; một điểm kh&aacute;c biệt mang t&iacute;nh sống c&ograve;n: <strong>Immutable (Kh&ocirc;ng thể thay đổi)</strong>. Một khi bạn đ&atilde; tạo ra một Tuple, bạn KH&Ocirc;NG THỂ th&ecirc;m, x&oacute;a, hay sửa bất kỳ phần tử n&agrave;o b&ecirc;n trong n&oacute;.</p><p><strong>C&uacute; ph&aacute;p:</strong> D&ugrave;ng ngoặc tr&ograve;n <code>()</code> thay v&igrave; ngoặc vu&ocirc;ng <code>[]</code>.</p><div class=\"code-block\"><pre><code><span class=\"hljs-comment\"># Tạo một Tuple lưu trữ cấu h&igrave;nh cố định</span>\ndb_config = (<span class=\"hljs-string\">\"localhost\"</span>, <span class=\"hljs-string\">\"root\"</span>, <span class=\"hljs-string\">\"password123\"</span>, <span class=\"hljs-number\">3306</span>)\n\n<span class=\"hljs-comment\"># Truy xuất giống hệt List (d&ugrave;ng Index)</span>\nprint(<span class=\"hljs-string\">\"Port kết nối:\"</span>, db_config[<span class=\"hljs-number\">3</span>])  <span class=\"hljs-comment\"># Output: 3306</span>\n\n<span class=\"hljs-comment\"># CỐ T&Igrave;NH SỬA SẼ BỊ LỖI (TypeError)</span>\n<span class=\"hljs-comment\"># db_config[1] = \"admin\"  &lt;-- D&ograve;ng n&agrave;y sẽ l&agrave;m sập chương tr&igrave;nh</span>\n</code></pre></div><p><strong>Tại sao phải d&ugrave;ng Tuple?</strong></p><ul><li><p><strong>Bảo vệ dữ liệu:</strong> Giả sử bạn viết một tool tự động h&oacute;a click chuột, tọa độ X v&agrave; Y tr&ecirc;n m&agrave;n h&igrave;nh l&agrave; cố định. Việc lưu ch&uacute;ng v&agrave;o Tuple <code>(x, y)</code> đảm bảo trong qu&aacute; tr&igrave;nh code chạy, kh&ocirc;ng c&oacute; thao t&aacute;c nhầm lẫn n&agrave;o l&agrave;m sai lệch tọa độ n&agrave;y.</p></li><li><p><strong>Tối ưu hiệu suất:</strong> Tuple tốn &iacute;t bộ nhớ v&agrave; được Python duyệt nhanh hơn List.</p></li></ul>', 0, '2026-03-15 05:06:59.636', '2026-03-15 05:06:59.636'),
('cmmralrcl00136utnp1utjzk0', 'cmmralrck00116utn4i77xgvh', 'Dictionary - Cấu trúc Key-Value', '<h2>2. Dictionary - Từ điển Dữ liệu (Key-Value)</h2><p><strong>Kh&aacute;i niệm:</strong> Nếu List v&agrave; Tuple d&ugrave;ng <strong>Index</strong> (0, 1, 2...) để t&igrave;m phần tử, th&igrave; Dictionary (Dict) d&ugrave;ng <strong>Key (Kh&oacute;a)</strong> để t&igrave;m <strong>Value (Gi&aacute; trị)</strong>. N&oacute; giống như một cuốn từ điển thực sự: bạn t&igrave;m từ kh&oacute;a (Key) để xem phần giải nghĩa (Value) của n&oacute;.</p><p><strong>Đặc điểm:</strong></p><ul><li>Dữ liệu lưu dưới dạng cặp <code>Key: Value</code>.</li><li>Kh&ocirc;ng c&oacute; thứ tự cố định (từ Python 3.7 trở l&ecirc;n th&igrave; c&oacute; giữ thứ tự th&ecirc;m v&agrave;o, nhưng ta vẫn lu&ocirc;n truy xuất bằng Key).</li><li><strong>Key phải l&agrave; duy nhất</strong> v&agrave; thường l&agrave; chuỗi (String) hoặc số.</li></ul><p><strong>C&uacute; ph&aacute;p:</strong> D&ugrave;ng ngoặc nhọn <code>{}</code>.</p><div class=\"code-block\"><pre><code><span class=\"hljs-comment\"># Thay v&igrave; d&ugrave;ng List kh&oacute; nhớ index, ta d&ugrave;ng Dict để m&ocirc; tả một thực thể</span>\ncandidate_profile = {\n    <span class=\"hljs-string\">\"name\"</span>: <span class=\"hljs-string\">\"Nguyễn Văn A\"</span>,\n    <span class=\"hljs-string\">\"email\"</span>: <span class=\"hljs-string\">\"nva@gmail.com\"</span>,\n    <span class=\"hljs-string\">\"skills\"</span>: [<span class=\"hljs-string\">\"Python\"</span>, <span class=\"hljs-string\">\"React\"</span>, <span class=\"hljs-string\">\"Laravel\"</span>],\n    <span class=\"hljs-string\">\"status\"</span>: <span class=\"hljs-string\">\"Đang phỏng vấn\"</span>\n}\n</code></pre></div><h2>a. Truy xuất dữ liệu trong Dictionary</h2><p>C&oacute; hai c&aacute;ch để lấy gi&aacute; trị ra: d&ugrave;ng ngoặc vu&ocirc;ng <code>[]</code> hoặc phương thức <code>.get()</code>.</p><div class=\"code-block\"><pre><code><span class=\"hljs-comment\"># C&aacute;ch 1: D&ugrave;ng ngoặc vu&ocirc;ng (Sẽ b&aacute;o lỗi nếu Key kh&ocirc;ng tồn tại)</span>\nprint(candidate_profile[<span class=\"hljs-string\">\"name\"</span>])  <span class=\"hljs-comment\"># Output: Nguyễn Văn A</span>\n\n<span class=\"hljs-comment\"># C&aacute;ch 2: D&ugrave;ng .get() (An to&agrave;n hơn, trả về None nếu Key kh&ocirc;ng tồn tại)</span>\nprint(candidate_profile.get(<span class=\"hljs-string\">\"experience\"</span>))  <span class=\"hljs-comment\"># Output: None</span>\n</code></pre></div><h2>b. Th&ecirc;m, Sửa v&agrave; X&oacute;a trong Dictionary</h2><p>Dict l&agrave; cấu tr&uacute;c dữ liệu <strong>Mutable</strong> (c&oacute; thể thay đổi).</p><div class=\"code-block\"><pre><code><span class=\"hljs-comment\"># 1. Th&ecirc;m hoặc Sửa: Chỉ cần gọi Key v&agrave; g&aacute;n gi&aacute; trị</span>\n<span class=\"hljs-comment\"># Sửa trạng th&aacute;i (V&igrave; key \"status\" đ&atilde; tồn tại)</span>\ncandidate_profile[<span class=\"hljs-string\">\"status\"</span>] = <span class=\"hljs-string\">\"Đ&atilde; nhận việc\"</span>\n\n<span class=\"hljs-comment\"># Th&ecirc;m số điện thoại (V&igrave; key \"phone\" chưa tồn tại)</span>\ncandidate_profile[<span class=\"hljs-string\">\"phone\"</span>] = <span class=\"hljs-string\">\"0987654321\"</span>\n\n<span class=\"hljs-comment\"># 2. X&oacute;a: D&ugrave;ng từ kh&oacute;a del hoặc pop()</span>\n<span class=\"hljs-comment\"># X&oacute;a email</span>\ndel candidate_profile[<span class=\"hljs-string\">\"email\"</span>]\n\n<span class=\"hljs-comment\"># X&oacute;a v&agrave; lấy ra gi&aacute; trị trạng th&aacute;i</span>\ncurrent_status = candidate_profile.pop(<span class=\"hljs-string\">\"status\"</span>)\n</code></pre></div>', 1, '2026-03-15 05:06:59.636', '2026-03-15 05:06:59.636'),
('cmmralrcl00146utn2oy1tgd9', 'cmmralrck00116utn4i77xgvh', 'Ứng dụng và So sánh các cấu trúc dữ liệu', '<h2>3. Kiến Thức Thực Tế (G&oacute;c nh&igrave;n chuy&ecirc;n gia)</h2><p>Khi bạn x&acirc;y dựng hệ thống web, đặc biệt l&agrave; viết API, Dictionary ch&iacute;nh l&agrave; \"linh hồn\". Mọi dữ liệu giao tiếp giữa Frontend v&agrave; Backend (hoặc giữa client v&agrave; server) hiện nay hầu hết đều d&ugrave;ng chuẩn <strong>JSON</strong>.</p><p>Về bản chất, JSON v&agrave; Dictionary của Python c&ó; cấu tr&uacute;c cực kỳ giống nhau. Khi bạn call một đường dẫn API (v&iacute; dụ như gọi <code>api/ping</code> để kiểm tra server xem c&ó; bị lỗi 503 hay kh&ocirc;ng), cục dữ liệu trả về nếu th&agrave;nh c&ocirc;ng thường sẽ được Python parse (ph&acirc;n t&iacute;ch) thẳng th&agrave;nh một Dictionary để bạn dễ d&agrave;ng b&oacute;c t&aacute;ch th&ocirc;ng tin: <code>response[\"status\"]</code> hoặc <code>response[\"message\"]</code>. Nắm chắc Dictionary l&agrave; bạn đ&atilde; cầm chắc tấm v&eacute; để l&agrave;m việc với bất kỳ API n&agrave;o.</p><h2>4. Tổng Kết</h2><table><thead><tr><td><strong>Đặc điểm</strong></td><td><strong>List</strong></td><td><strong>Tuple</strong></td><td><strong>Dictionary</strong></td></tr></thead><tbody><tr><td><strong>C&uacute; ph&aacute;p</strong></td><td><code>[1, 2, 3]</code></td><td><code>(1, 2, 3)</code></td><td><code>{\"id\": 1, \"name\": \"A\"}</code></td></tr><tr><td><strong>Truy xuất</strong></td><td>Bằng Index (0, 1...)</td><td>Bằng Index (0, 1...)</td><td>Bằng Key</td></tr><tr><td><strong>Thay đổi (Mutable)</strong></td><td>C&oacute;</td><td><strong>Kh&ocirc;ng (Chỉ đọc)</strong></td><td>C&ó;</td></tr><tr><td><strong>Ứng dụng ch&iacute;nh</strong></td><td>Danh s&aacute;ch linh hoạt</td><td>Dữ liệu cố định, cấu h&igrave;nh</td><td>Lưu trữ đối tượng, API</td></tr></tbody></table>', 2, '2026-03-15 05:06:59.636', '2026-03-15 05:06:59.636'),
('cmmrc071h00196utnltha1g42', 'cmmrc071h00186utnqblnr73q', 'Khái niệm Set và Cú pháp cơ bản', '<h2>1. Set (Tập hợp) là gì?</h2><p>Nếu bạn còn nhớ môn Toán cấp 2, chúng ta đã từng học về \"Tập hợp\". <strong>Set</strong> trong Python được thiết kế y hệt như vậy.</p><p><strong>3 Đặc điểm cốt lõi của Set:</strong></p><ol><li><p><strong>Không có thứ tự (Unordered):</strong> Các phần tử trong Set không có vị trí (Index) cố định. Bạn in ra 10 lần thì thứ tự của chúng có thể đảo lộn 10 lần.</p></li><li><p><strong>Không chứa phần tử trùng lặp (Unique):</strong> Đây là \"siêu năng lực\" của Set. Nếu bạn cố tình đưa vào 5 phần tử giống nhau, Set sẽ tự động gộp chúng lại chỉ còn 1.</p></li><li><p><strong>Có thể thay đổi (Mutable):</strong> Bạn có thể thêm hoặc xóa phần tử trong Set.</p></li></ol><p><strong>Cú pháp:</strong> Dùng ngoặc nhọn <code>{}</code> giống Dictionary, nhưng <strong>chỉ chứa giá trị</strong> chứ không phải cặp <code>Key: Value</code>.</p><div class=\"code-block\"><pre><code class=\"code-container formatted\"># 1. Tạo một Set\nunique_numbers = {1, 2, 3, 4, 5}\n\n# 2. Tạo một Set từ List có phần tử trùng lặp (Kỹ thuật cực hay dùng)\ntags_list = [\"python\", \"web\", \"python\", \"ai\", \"web\"]\ntags_set = set(tags_list)\n\nprint(tags_set) \n# Output sẽ tự động lọc trùng: {\'ai\', \'python\', \'web\'} (Thứ tự có thể khác)\n\n# 3. CHÚ Ý: Tạo Set rỗng\nempty_set = set() # Phải dùng set(), nếu dùng {} Python sẽ hiểu là Dictionary rỗng\n</code></pre></div>', 0, '2026-03-15 05:46:12.773', '2026-03-15 05:46:12.773'),
('cmmrc071h001a6utnhv1jxwse', 'cmmrc071h00186utnqblnr73q', 'Thao tác với Set, Ứng dụng và Tổng quan', '<h2>2. Các thao tác cơ bản với Set</h2><p>Vì không có Index, bạn <strong>không thể</strong> truy xuất Set bằng kiểu <code>my_set[0]</code>. Thay vào đó, chúng ta thường dùng vòng lặp để duyệt qua Set, hoặc dùng các phương thức sau:</p><h3>a. Thêm và Xóa</h3><div class=\"code-block\"><pre><code class=\"code-container formatted\">skills = {\"HTML\", \"CSS\"}\n\n# Thêm 1 phần tử\nskills.add(\"JavaScript\")\n\n# Xóa 1 phần tử (sẽ báo lỗi nếu không tồn tại)\nskills.remove(\"CSS\")\n\n# Xóa an toàn (không báo lỗi nếu không tồn tại)\nskills.discard(\"React\") \n</code></pre></div><h3>b. Các phép toán Tập hợp (Toán học)</h3><p>Đây là lúc Set thể hiện sức mạnh tuyệt đối khi bạn cần so sánh dữ liệu giữa 2 nhóm.</p><div class=\"code-block\"><pre><code class=\"code-container formatted\">group_A = {\"Python\", \"Java\", \"C++\"}\ngroup_B = {\"Python\", \"JavaScript\", \"PHP\"}\n\n# 1. Giao của 2 tập hợp (Lấy phần tử chung) - Dùng dấu &\nprint(group_A &amp; group_B) # Output: {\'Python\'}\n\n# 2. Hợp của 2 tập hợp (Lấy tất cả, không lấy trùng) - Dùng dấu |\nprint(group_A | group_B) # Output: {\'Java\', \'C++\', \'Python\', \'JavaScript\', \'PHP\'}\n\n# 3. Hiệu của 2 tập hợp (Có ở A nhưng không có ở B) - Dùng dấu -\nprint(group_A - group_B) # Output: {\'Java\', \'C++\'}\n</code></pre></div><hr><h2>3. Kiến Thức Thực Tế (Góc nhìn chuyên gia)</h2><p>Trong các dự án thực tế, Set được dùng nhiều nhất để <strong>làm sạch dữ liệu</strong> và <strong>tăng tốc độ tìm kiếm</strong>.</p><p>Giả sử bạn có một danh sách 1 triệu ID người dùng đã truy cập website và bạn muốn kiểm tra xem ID <code>9999</code> có nằm trong đó không.</p><ul><li><p>Nếu lưu bằng <strong>List</strong>: Python phải tìm từ đầu đến cuối, mất thời gian <span class=\"math-inline\">$O(n)$</span>.</p></li><li><p>Nếu lưu bằng <strong>Set</strong>: Python sử dụng một cơ chế gọi là Hash Table, nó có thể biết ngay lập tức ID đó có tồn tại hay không, mất thời gian chỉ <span class=\"math-inline\">$O(1)$</span> (nhanh như chớp).</p></li></ul><blockquote><p><strong>💡 Mẹo:</strong> Bất cứ khi nào bạn nhận được yêu cầu: <em>\"Hãy lọc ra danh sách các thẻ tag duy nhất từ các bài viết\"</em> hoặc <em>\"Tìm những nhân viên có mặt ở cả ca sáng và ca chiều\"</em>, hãy nghĩ ngay đến <strong>Set</strong>.</p></blockquote><hr><h2>4. Bảng Tổng Kết \"Tứ Đại Kim Cương\"</h2><p>Đây là bảng \"cứu cánh\" bạn nên ghi nhớ để chọn đúng cấu trúc dữ liệu khi thiết kế phần mềm:</p><table><thead><tr><td><strong>Đặc điểm</strong></td><td><strong>List []</strong></td><td><strong>Tuple ()</strong></td><td><strong>Dictionary {}</strong></td><td><strong>Set {}</strong></td></tr></thead><tbody><tr><td><strong>Có thứ tự (Index)</strong></td><td>✅ Có</td><td>✅ Có</td><td>❌ Không (Dùng Key)</td><td>❌ Không</td></tr><tr><td><strong>Cho phép trùng lặp</strong></td><td>✅ Có</td><td>✅ Có</td><td>❌ Không (Key phải duy nhất)</td><td>❌ Không</td></tr><tr><td><strong>Sửa đổi (Mutable)</strong></td><td>✅ Có</td><td>❌ Không (Chỉ đọc)</td><td>✅ Có</td><td>✅ Có</td></tr><tr><td><strong>Ứng dụng tốt nhất</strong></td><td>Dữ liệu có thứ tự, cần sắp xếp</td><td>Dữ liệu cố định, cấu hình</td><td>Lưu trữ đối tượng, mô tả thực thể</td><td>Lọc trùng lặp, kiểm tra tồn tại cực nhanh</td></tr></tbody></table>', 1, '2026-03-15 05:46:12.773', '2026-03-15 05:46:12.773');

